import React from 'react'
import { Row, Paragraph, Separator, Image, usePageWidth, Divider, FlowGrid } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import { css, cx } from '@linaria/core'
import { boolAttr } from '@fs/zion-frontend-friends'
import { TransparentCard, LeftDivider, imageMap, linkCss, LinksSection } from './shared'
import { useExternalUrl } from '../../ExternalContext'

const helpHeaderLinkCss = css`
  font-weight: bold;
  &[large] {
    font-size: 20px !important;
  }
`
const positionSupportAreaButtonCss = css`
  position: relative;
  top: var(--spacer-md);
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  max-width: 160px;
  margin: 0 auto;
  overflow: hidden;

  &[small-screen] {
    margin: 0 12px;
    max-width: calc(100% + 2 * var(--spacer-xs));
    top: var(--spacer-nano);
    left: calc(-1 * var(--spacer-xs));
    align-items: start;
    text-align: start;
  }
`

function HeaderLink({ id, url, text, Icon: imageString, sub }) {
  const atWidth = usePageWidth()
  const toExternalUrl = useExternalUrl()
  const IconSize = atWidth({ default: 24, sm: 48 })
  return (
    <>
      <Row>
        {imageString && <Image alt="" src={imageMap[imageString]} width={IconSize} height={IconSize} />}
        <Link
          className={cx(linkCss, helpHeaderLinkCss)}
          to={toExternalUrl(url)}
          linkName={id}
          large={boolAttr(atWidth({ default: false, sm: true }))}
          alignY="middle"
          external
        >
          {text}
          <span> &gt;</span>
        </Link>
      </Row>
      <Separator size={imageString ? 'xs' : atWidth({ default: 'xs', sm: 'sm' })} />
      <Paragraph size="xs" secondary>
        {sub.text}
      </Paragraph>
      <Separator size="xs" />
      <Divider />
    </>
  )
}

function HeaderNoLink({ text, Icon: imageString, sub }) {
  const atWidth = usePageWidth()
  const IconSize = atWidth({ default: 24, sm: 48 })
  return (
    <>
      <Row>
        {imageString && <Image alt="" src={imageMap[imageString]} width={IconSize} height={IconSize} />}
        <div
          className={cx(linkCss, helpHeaderLinkCss)}
          large={boolAttr(atWidth({ default: false, sm: true }))}
          alignY="middle"
        >
          {text}
          <span> &gt;</span>
        </div>
      </Row>
      <Separator size={imageString ? 'xs' : atWidth({ default: 'xs', sm: 'sm' })} />
      <Paragraph size="xs" secondary>
        {sub.text}
      </Paragraph>
      <Separator size="xs" />
      <Divider />
    </>
  )
}

function SupportArea({ imageString, text }) {
  const atWidth = usePageWidth()
  const isSmallScreen = atWidth({ default: true, sm: false })
  return (
    <div className={positionSupportAreaButtonCss} small-screen={boolAttr(isSmallScreen)}>
      <Separator size={isSmallScreen ? 'xs' : 'hide'} />
      <Image alt="" src={imageMap[imageString]} width={64} height={64} />
      <Separator size={isSmallScreen ? 'xs' : 'md'} />
      <Paragraph size="xs" dense secondary>
        {text}
      </Paragraph>
      <Separator size={isSmallScreen ? 'xs' : 'md'} />
    </div>
  )
}

export default function Help({ firstSet, secondSet, thirdSet }) {
  const atWidth = usePageWidth()

  return (
    <FlowGrid columnCount={atWidth({ sm: 2, xl: 3 })} gutters={atWidth({ default: 'xxs', sm: 'xxl' })}>
      <>
        <Separator size="xxs" />
        <HeaderLink {...firstSet?.sub?.[0].sub[0]} sub={firstSet?.sub?.[0].sub[1]} />
        <LinksSection {...firstSet?.sub?.[1]} />
      </>
      {secondSet && atWidth({ default: <Divider />, sm: null })}
      {secondSet && (
        <>
          <Separator size="xxs" />
          <HeaderLink {...secondSet.sub?.[0].sub[0]} sub={secondSet.sub?.[0].sub[1]} />
          <LinksSection {...secondSet.sub?.[1]} />
        </>
      )}
      {thirdSet && atWidth({ default: <Divider />, sm: null })}
      {thirdSet && (
        <LeftDivider showLeftDivider={atWidth({ default: false, xl: true })}>
          <Separator size="nano" />
          <TransparentCard to={thirdSet.sub?.[1]?.url} linkName={thirdSet.id} external>
            <Separator size="xxs" />
            <HeaderNoLink id={thirdSet.id} text={thirdSet.text} sub={thirdSet.sub?.[0]} />
            <SupportArea imageString={thirdSet.sub?.[1]?.Icon} text={thirdSet.sub?.[1]?.text} />
            <Separator size="xxs" />
          </TransparentCard>
        </LeftDivider>
      )}
    </FlowGrid>
  )
}
