import React from 'react'
import { colors } from '@fs/zion-ui'
import { css } from '@linaria/core'

const leftDividerCss = css`
  position: relative;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: calc(var(--gutters-x) * -1);
    bottom: 0;
    width: 1px;
    background-color: ${colors.gray10};
  }
`

export default function LeftDivider({ showLeftDivider, children }) {
  return <div className={showLeftDivider ? leftDividerCss : null}>{children}</div>
}
