import React from 'react'
import { Affordance } from '@fs/zion-ui/quarks-authorized-use-only'
import { colors } from '@fs/zion-ui'
import { css, cx } from '@linaria/core'
import { useExternalUrl } from '../../../ExternalContext'

const affordanceCss = css`
  &:hover,
  &:focus,
  &:active {
    background-color: ${colors.gray00} !important;
  }
`

export default function TransparentCard({ to, className, ...props }) {
  const toExternalUrl = useExternalUrl()
  return <Affordance {...props} to={toExternalUrl(to)} className={cx(affordanceCss, className)} />
}
