import React, { useEffect, useRef } from 'react'
import PropTypes from 'prop-types'
import { Row, Separator, Divider, LayoutBand, useEscHandler } from '@fs/zion-ui'
import { Menu, MenuClose, Person } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { useZionAxios } from '@fs/zion-axios'
import { trackEvent } from '@fs/zion-analytics'
import FSLogo from '../shared/components/FSLogo/FSLogo'
import LanguagePicker from '../shared/components/LanguagePicker'
import { AuthAccount } from '../shared/components'
import { HeaderIconButton, useHeaderBreakString } from '../shared'
import { useHeaderButtons, NavigationButtons, Navigation, AuthMenu } from './HeaderNavigation'
import ExternalContext from './ExternalContext'

function StartContentLargeScreen({ navigationData, headerButtonsState, external }) {
  return (
    <Row>
      <div>
        <Separator size="nano" />
        <FSLogo gray useBaseUrl={external} />
      </div>
      <NavigationButtons navigationData={navigationData} {...headerButtonsState} desktop />
    </Row>
  )
}
function EndContentLargeScreen({ external, hideLanguagePicker }) {
  return (
    <Row gutters="xxs">
      {!hideLanguagePicker && <LanguagePicker />}
      <AuthAccount gray external={external} />
    </Row>
  )
}

function StartContentSmallScreen({ headerButtonsState, external }) {
  const { navigationMenuOpen, setNavigationButtonOpen } = headerButtonsState
  const headerIconButtonProps = navigationMenuOpen
    ? {
        title: 'Close Navigation',
        'aria-label': 'Close Navigation',
        Icon: MenuClose,
        onClick: () => {
          trackEvent({ event_name: 'header:navigationMenu:closed' })
          setNavigationButtonOpen(false)
        },
      }
    : {
        title: 'Open Navigation',
        'aria-label': 'Open Navigation',
        Icon: Menu,
        onClick: () => {
          trackEvent({ event_name: 'header:navigationMenu:opened' })
          setNavigationButtonOpen(true)
        },
      }

  return (
    <Row>
      <HeaderIconButton {...headerIconButtonProps} />
      <FSLogo gray useBaseUrl={external} />
    </Row>
  )
}

function EndContentSmallScreen({ headerButtonsState, hideLanguagePicker }) {
  const { isAuthAccountMenuOpen, setIsAuthAccountMenuOpen } = headerButtonsState
  const headerIconButtonProps = isAuthAccountMenuOpen
    ? {
        title: 'Close Account Options',
        'aria-label': 'Close Account Options',
        Icon: MenuClose,
        onClick: () => {
          trackEvent({ event_name: 'header:accountMenu:closed' })
          setIsAuthAccountMenuOpen(false)
        },
      }
    : {
        title: 'Open Account Options',
        'aria-label': 'Open Account Options',
        Icon: Person,
        onClick: () => {
          trackEvent({ event_name: 'header:accountMenu:opened' })
          setIsAuthAccountMenuOpen(true)
        },
      }

  return (
    <Row>
      {!hideLanguagePicker && <LanguagePicker />}
      <HeaderIconButton {...headerIconButtonProps} />
    </Row>
  )
}

export default function UnauthenticatedHeader({ config = {} }) {
  const { external, hideLanguagePicker = false } = config
  const [{ data }] = useZionAxios('/service/home/utils/chef/unauthenticated-header')
  const navigationData = data?.header
  const headerButtonsState = useHeaderButtons()
  const { navigationMenuOpen, setNavigationButtonOpen } = headerButtonsState

  const dir = i18n.dir()
  const headerRef = useRef(null)
  const leftSectionRef = useRef(null)
  const rightSectionRef = useRef(null)
  const breakString = useHeaderBreakString({ headerRef, leftSectionRef, rightSectionRef })
  const isLargeScreen = breakString === 'desktop'
  const StartContent = isLargeScreen ? StartContentLargeScreen : StartContentSmallScreen
  const EndContent = isLargeScreen ? EndContentLargeScreen : EndContentSmallScreen

  useEffect(() => {
    if (!navigationMenuOpen) return undefined
    // using event.composedPath to handle clicks in the shadow dom
    const handlePointerDown = (event) => {
      const headerElement = headerRef.current
      if (!headerElement) return
      const composedPath = typeof event.composedPath === 'function' ? event.composedPath() : undefined
      const isClickInsideHeader =
        composedPath?.length > 0 ? composedPath.includes(headerElement) : headerElement.contains(event.target)
      if (!isClickInsideHeader) {
        trackEvent({ event_name: 'header:navigationMenu:closed' })
        setNavigationButtonOpen(false)
      }
    }

    document.addEventListener('mousedown', handlePointerDown)
    document.addEventListener('touchstart', handlePointerDown)

    return () => {
      document.removeEventListener('mousedown', handlePointerDown)
      document.removeEventListener('touchstart', handlePointerDown)
    }
  }, [navigationMenuOpen, setNavigationButtonOpen])

  useEscHandler({
    enabled: navigationMenuOpen,
    handler: () => {
      trackEvent({ event_name: 'header:navigationMenu:closed' })
      setNavigationButtonOpen(false)
    },
  })

  return (
    <ExternalContext.Provider value={external}>
      <header role="banner" aria-label="Main navigation" data-testid="unauthenticated-header" ref={headerRef}>
        <LayoutBand marginX={isLargeScreen ? 'sm' : 'nano'} marginY={isLargeScreen ? 'none' : 'nano'} maxWidth="md">
          <Row break={breakString} guttersX="none" alignY="middle">
            <div id="left-section" ref={dir === 'ltr' ? leftSectionRef : rightSectionRef}>
              <StartContent
                navigationData={navigationData}
                headerButtonsState={headerButtonsState}
                external={external}
              />
            </div>
            <div growX />
            <div id="right-section" ref={dir === 'ltr' ? rightSectionRef : leftSectionRef}>
              <EndContent
                headerButtonsState={headerButtonsState}
                external={external}
                hideLanguagePicker={hideLanguagePicker}
              />
            </div>
          </Row>
        </LayoutBand>
        <Divider fullWidth />
        {!isLargeScreen && <AuthMenu {...headerButtonsState} />}
        <Navigation desktop={isLargeScreen} navigationData={navigationData} {...headerButtonsState} />
      </header>
    </ExternalContext.Provider>
  )
}

UnauthenticatedHeader.propTypes = {
  config: PropTypes.shape({
    external: PropTypes.bool,
    hideLanguagePicker: PropTypes.bool,
  }),
}
