import React from 'react'
import { Row, H3, Separator, colors, Card, Image, usePageWidth, FlowGrid, WhiteTheme } from '@fs/zion-ui'
import { TransparentCard, imageMap } from './shared'
import { useExternalUrl } from '../../ExternalContext'

function NavCardNoSubtextDense({ id, to, Image: imageString, text }) {
  return (
    <TransparentCard to={to} linkName={id}>
      <Separator size="xs" />
      <Row>
        <Image src={imageMap[imageString]} width={24} height={24} />
        <H3 size="H6" supplementary>
          {text}
        </H3>
      </Row>
      <Separator size="xs" />
    </TransparentCard>
  )
}
function ReverseText({ children, reverse }) {
  // see https://beta.familysearch.org/frontier/zion/?path=/docs/ui-foundation-colors--docs for when text should be reversed (white instead of black)
  if (reverse) {
    return <WhiteTheme>{children}</WhiteTheme>
  }
  return children
}
function NavCardWithBackground({ id, Icon: imageString, text, url, backgroundColor }) {
  const atWidth = usePageWidth()
  const toExternalUrl = useExternalUrl()
  const isSmallScreen = atWidth({ default: true, sm: false })
  if (isSmallScreen) {
    return <NavCardNoSubtextDense id={id} to={toExternalUrl(url)} Image={imageString} text={text} external />
  }
  return (
    <Card backgroundColor={colors[backgroundColor]} to={toExternalUrl(url)} linkName={id} external>
      <Image src={imageMap[imageString]} alt="" width={40} height={40} />
      <Separator size="xl" />
      <ReverseText reverse={backgroundColor.match(/\d+/)?.[0] > 40}>
        <H3 size="H6" supplementary>
          {text}
        </H3>
      </ReverseText>
    </Card>
  )
}

export default function Benefits({ firstSet }) {
  const atWidth = usePageWidth()

  return (
    <FlowGrid
      columnCount={atWidth({ sm: 2, md: 3, xl: 4 })}
      guttersY={atWidth({ default: 'xxs', sm: 'sm' })}
      guttersX={atWidth({ default: 'xxs', sm: 'sm', xxl: 'lg' })}
    >
      {firstSet?.sub?.map((stuff) => (
        <NavCardWithBackground key={stuff.id} {...stuff} />
      ))}
    </FlowGrid>
  )
}
