import { createContext, useContext } from 'react'
import { baseUrl } from '@fs/zion-config'

const ExternalContext = createContext(false)

export function useExternal() {
  return useContext(ExternalContext)
}

export function useExternalUrl() {
  const external = useContext(ExternalContext)
  return (url) =>
    external && url && baseUrl && url.startsWith('/') && !url.startsWith('//') ? `${baseUrl}${url}` : url
}

export default ExternalContext
