import React from 'react'
import { usePageWidth, Divider, FlowGrid } from '@fs/zion-ui'
import { LeftDivider, LinksSection, MultiLinkSections } from './shared'

export default function About({ firstSet, secondSet }) {
  const atWidth = usePageWidth()
  return (
    <FlowGrid columnCount={atWidth({ sm: 2, md: 3, xl: 4 })} gutters={atWidth({ default: 'md', xl: 'xxl' })}>
      {firstSet?.sub?.map((linkSet) =>
        linkSet?.type === 'linkGroup' ? (
          <MultiLinkSections key={linkSet.id} {...linkSet} />
        ) : (
          <LinksSection key={linkSet.id} {...linkSet} />
        )
      )}
      {atWidth({ default: <Divider />, sm: null })}
      <LeftDivider showLeftDivider={atWidth({ default: false, xl: true })}>
        {secondSet?.sub?.map((stuff) => (
          <LinksSection key={stuff.id} {...stuff} />
        ))}
      </LeftDivider>
    </FlowGrid>
  )
}
