import React from 'react'
import { colors, FlowGrid, H3, Paragraph, Separator } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import { boolAttr } from '@fs/zion-frontend-friends'
import { css } from '@linaria/core'
import { useExternalUrl } from '../../../ExternalContext'

// css loaded in different order on app. !important to override this.
export const linkCss = css`
  display: block;
  padding: 2px !important;
  color: ${colors.transparent.gray70} !important;
  text-decoration: none;
  text-wrap: balance;

  &[inline] {
    display: inline-block;
  }
  &[underline] {
    text-decoration: underline;
  }
  &:hover,
  &:focus {
    text-decoration: underline;
  }
  &[no-hover] {
    &[no-hover]:hover,
    &[no-hover]:focus {
      text-decoration: none;
    }
  }
`

export function HeaderNavLink({ id, url, underline, inline, children }) {
  const toExternalUrl = useExternalUrl()
  return (
    <Link
      className={linkCss}
      to={toExternalUrl(url)}
      linkName={id}
      underline={boolAttr(underline)}
      inline={boolAttr(inline)}
      external
    >
      {children}
      <span> &gt;</span>
    </Link>
  )
}

export function LinksSection({ text, sub: links }) {
  return (
    <>
      {text && text !== 'None' && (
        <>
          <H3 size="H6" supplementary>
            {text}
          </H3>
          <Separator size="xxs" />
        </>
      )}
      {text && text === 'None' && <Separator size="xxs" />}
      {links.map((link) => (
        <Paragraph key={link.id} size="xs" dense>
          <HeaderNavLink {...link}>{link.text}</HeaderNavLink>
        </Paragraph>
      ))}
    </>
  )
}

export function MultiLinkSections({ sub: linkSections }) {
  return (
    <FlowGrid>
      {linkSections?.map((linkSection) => (
        <LinksSection key={linkSection.id} {...linkSection} />
      ))}
    </FlowGrid>
  )
}
