import React, { useReducer, useCallback } from 'react'
import { colors, Row } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { HorizontalScroller } from '@fs/zion-ui/quarks-authorized-use-only'
import NavButtonRow from './HeaderNavButton'
import { SectionContent } from './SectionNavContent/SectionNavContent'
import NavSheet from './NavSheet'
import { AuthAccount } from '../../shared/components'
import { useExternal } from '../ExternalContext'

const navButtonsBackgroundCss = css`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 52px;
  background-color: ${colors.gray00};
`
const AuthOverlayCss = css`
  background-color: ${colors.gray00};
  padding: 12px 16px;
  border-bottom: 1px solid ${colors.gray10};
`

function headerButtonsReducer(state, action) {
  switch (action.type) {
    case 'SET_ACTIVE_NAVIGATION_MENU':
      return { ...state, activeNavMenu: action.index }
    case 'OPEN_NAVIGATION_MENU':
      return { ...state, navigationMenuOpen: true, isAuthAccountMenuOpen: false, navigationMenuHidden: false }
    case 'CLOSE_NAVIGATION_MENU':
      return { ...state, navigationMenuOpen: false }
    case 'OPEN_AUTH_ACCOUNT_MENU':
      return { ...state, isAuthAccountMenuOpen: true, navigationMenuOpen: false, accountMenuHidden: false }
    case 'CLOSE_AUTH_ACCOUNT_MENU':
      return { ...state, isAuthAccountMenuOpen: false }
    case 'CLOSE_NAVIGATION_TRANSITION_FINISHED':
      return { ...state, navigationMenuHidden: true }
    case 'CLOSE_AUTH_ACCOUNT_TRANSITION_FINISHED':
      return { ...state, accountMenuHidden: true }
    default:
      return state
  }
}

export function useHeaderButtons() {
  const [state, dispatch] = useReducer(headerButtonsReducer, {
    activeNavMenu: 0,
    navigationMenuOpen: false,
    isAuthAccountMenuOpen: false,
    navigationMenuHidden: true,
    accountMenuHidden: true,
  })

  const setActiveNavigationMenu = useCallback((index) => {
    dispatch({ type: 'SET_ACTIVE_NAVIGATION_MENU', index })
  }, [])

  const setNavigationButtonOpen = useCallback((openNavigationMenu) => {
    if (openNavigationMenu) {
      dispatch({ type: 'OPEN_NAVIGATION_MENU' })
    } else {
      dispatch({ type: 'CLOSE_NAVIGATION_MENU' })
    }
  }, [])

  const setIsAuthAccountMenuOpen = useCallback((openAuthAccountMenu) => {
    if (openAuthAccountMenu) {
      dispatch({ type: 'OPEN_AUTH_ACCOUNT_MENU' })
    } else {
      dispatch({ type: 'CLOSE_AUTH_ACCOUNT_MENU' })
    }
  }, [])

  const onNavigationCloseTransitionFinished = useCallback(() => {
    dispatch({ type: 'CLOSE_NAVIGATION_TRANSITION_FINISHED' })
  }, [])

  const onAccountCloseTransitionFinished = useCallback(() => {
    dispatch({ type: 'CLOSE_AUTH_ACCOUNT_TRANSITION_FINISHED' })
  }, [])

  return {
    ...state,
    setActiveNavigationMenu,
    setNavigationButtonOpen,
    setIsAuthAccountMenuOpen,
    onNavigationCloseTransitionFinished,
    onAccountCloseTransitionFinished,
  }
}

export function Navigation({ desktop, navigationData, ...headerButtonsState }) {
  const [t] = useTranslation()
  const { navigationMenuOpen, navigationMenuHidden, onNavigationCloseTransitionFinished } = headerButtonsState
  const currentNavigation = navigationData?.[headerButtonsState.activeNavMenu] || {}
  const { id, sub } = currentNavigation
  const sectionHeadingId = sub?.[0]?.id ? `${sub[0].id}-heading` : undefined

  return (
    <nav role="navigation" aria-label={t('nav.main', 'Main')}>
      <NavSheet
        isOpen={navigationMenuOpen}
        hideNavSheet={navigationMenuHidden}
        onCloseFinished={onNavigationCloseTransitionFinished}
        ariaLabelledby={sectionHeadingId}
        transparent
      >
        {!desktop && (
          <>
            <div className={navButtonsBackgroundCss} />
            <HorizontalScroller>
              <NavButtonRow navigationData={navigationData} {...headerButtonsState} desktop={desktop} />
            </HorizontalScroller>
          </>
        )}
        {!navigationMenuHidden && <SectionContent id={id} sub={sub} desktop={desktop} headingId={sectionHeadingId} />}
      </NavSheet>
    </nav>
  )
}

export function NavigationButtons({ desktop, navigationData, ...headerButtonsState }) {
  const [t] = useTranslation()

  return (
    <nav role="navigation" aria-label={t('nav.mainMenu', 'Main menu')}>
      <NavButtonRow navigationData={navigationData} {...headerButtonsState} desktop={desktop} />
    </nav>
  )
}

export function AuthMenu({ isAuthAccountMenuOpen, accountMenuHidden, onAccountCloseTransitionFinished }) {
  const [t] = useTranslation()
  const external = useExternal()

  return (
    <NavSheet
      isOpen={isAuthAccountMenuOpen}
      hideNavSheet={accountMenuHidden}
      onCloseFinished={onAccountCloseTransitionFinished}
      ariaLabel={t('header.account', 'Account')}
    >
      <Row className={AuthOverlayCss} alignX="end">
        <AuthAccount gray external={external} />
      </Row>
    </NavSheet>
  )
}
