import React from 'react'
import { LayoutBand, H2, Paragraph, Separator, usePageWidth, Divider } from '@fs/zion-ui'
import Features from './Features'
import Benefits from './Benefits'
import Help from './Help'
import About from './About'
import { HeaderNavLink } from './shared'

export function SectionContent({ id, sub, desktop, headingId }) {
  const atWidth = usePageWidth()
  const [heading, firstSet, secondSet, thirdSet] = sub || []
  const { id: headingLinkId, text, sub: subHeading } = heading || {}
  const [{ text: subheadingText }, { text: subHeadingLinkText, url }] = subHeading || [{}, {}]
  const sectionHeadingId = headingId || (headingLinkId ? `${headingLinkId}-heading` : undefined)

  return (
    <LayoutBand marginY={desktop ? 'xl' : 'sm'} maxWidth="md">
      <H2 id={sectionHeadingId} size={desktop ? 'H4' : 'H5'} supplementary>
        {text}
      </H2>
      {subHeading && (
        <>
          <Separator size="nano" />
          <Paragraph size="xs" balanced>
            {subheadingText}{' '}
            <HeaderNavLink id={headingLinkId} url={url} underline inline>
              {subHeadingLinkText}
            </HeaderNavLink>
          </Paragraph>
        </>
      )}
      {atWidth({ default: <Divider marginY="xxs" />, sm: <Separator size="sm" /> })}
      {id === 'features' && <Features firstSet={firstSet} secondSet={secondSet} />}
      {id === 'benefits' && <Benefits firstSet={firstSet} />}
      {id === 'help' && <Help firstSet={firstSet} secondSet={secondSet} thirdSet={thirdSet} />}
      {id === 'about' && <About firstSet={firstSet} secondSet={secondSet} />}
    </LayoutBand>
  )
}
