import React from 'react'
import { Paragraph, Row, colors } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { boolAttr } from '@fs/zion-frontend-friends'
import { trackEvent } from '@fs/zion-analytics'

const navButtonCss = css`
  height: 52px;
  padding: 0 16px;
  position: relative;
  cursor: pointer;
  background-color: transparent;
  border: none;
  &:focus {
    outline: 2px solid ${colors.green10};
    outline-offset: -8px;
    border-radius: 20px;
  }
  &[desktop] {
    height: 64px;
  }
  &:focus:not(:focus-visible) {
    outline: none;
  }
  &[is-selected]:after {
    content: '';
    z-index: 4;
    position: absolute;
    bottom: 0;
    inset-inline-start: 16px;
    inset-inline-end: 16px;
    border: 2px solid transparent;
    border-color: ${colors.green10};
  }
  &[is-selected][desktop]:after {
    bottom: -4px;
  }
`
const navCss = css`
  width: 100%;
  justify-content: space-between;
`
function HeadingNavButton({
  id,
  title,
  navigationMenuOpen,
  activeNavMenu,
  index,
  setNavigationButtonOpen,
  setActiveNavigationMenu,
  desktop,
}) {
  const isSelected = navigationMenuOpen && index === activeNavMenu
  return (
    <button
      type="button"
      onClick={() => {
        if (!isSelected) {
          trackEvent({ event_name: `header:${id}:opened` })
          setNavigationButtonOpen(true)
          setActiveNavigationMenu(index)
        }
        if (desktop && navigationMenuOpen && isSelected) {
          trackEvent({ event_name: `header:${id}:closed` })
          setNavigationButtonOpen(false)
        }
      }}
      className={navButtonCss}
      aria-expanded={isSelected}
      desktop={boolAttr(desktop)}
      is-selected={boolAttr(isSelected)}
      tabIndex="0"
    >
      <Paragraph size="sm" secondary>
        {title}
      </Paragraph>
    </button>
  )
}

export default function NavButtonRow({ navigationData, desktop, ...headerButtonsState }) {
  return (
    <Row gutters="xxs" className={navCss}>
      {navigationData?.map(({ id, text }, index) => (
        <HeadingNavButton
          key={id}
          id={id}
          title={text}
          desktop={desktop}
          index={index}
          {...headerButtonsState}
          noShrinkX
        />
      ))}
    </Row>
  )
}
