import React from 'react'
import { css } from '@linaria/core'
import { useTheme } from '@fs/zion-ui'
import { Overlay, OpenCloseAnimation } from '@fs/zion-ui/quarks-authorized-use-only'
import { boolAttr } from '@fs/zion-frontend-friends'

const navigationOverlayCss = css`
  z-index: 3;
  position: absolute;
  left: 0;
  right: 0;
  overflow: hidden;
`
const backgroundCss = css`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(255, 253, 252, 0.949);
  backdrop-filter: blur(6px);

  &[night] {
    background-color: rgba(0, 1, 1, 0.875);
  }
`

export default function NavSheet({ ariaLabel, children, isOpen, hideNavSheet, onCloseFinished, ariaLabelledby }) {
  const theme = useTheme()

  if (hideNavSheet) {
    return null
  }
  return (
    <div className={navigationOverlayCss}>
      <OpenCloseAnimation
        isOpen={isOpen}
        openStyles={{
          transform: 'translateY(0%)',
        }}
        closeStyles={{
          transform: `translateY(-100%)`,
        }}
        onOpenFinished={() => {}}
        onCloseFinished={onCloseFinished}
      >
        <div className={backgroundCss} night={boolAttr(theme === 'night')} />
        <Overlay z={0} borderRadius={0} aria-label={ariaLabel} aria-labelledby={ariaLabelledby}>
          {children}
        </Overlay>
      </OpenCloseAnimation>
    </div>
  )
}
