import React from 'react'
import { Row, H3, Paragraph, Separator, Image, usePageWidth, FlowGrid } from '@fs/zion-ui'
import { boolAttr } from '@fs/zion-frontend-friends'
import { TransparentCard, imageMap, linkCss, MultiLinkSections } from './shared'

function LinkLookAlike({ text }) {
  return (
    <span className={linkCss} no-hover={boolAttr(true)}>
      <Paragraph size="sm" balanced>
        {text}
        <span> &gt;</span>
      </Paragraph>
    </span>
  )
}

function NavCard({ id, Image: imageString, sub, text }) {
  const atWidth = usePageWidth()
  const isSmallScreen = atWidth({ default: true, sm: false })
  const { url, text: linkText } = sub[0] || {}
  return (
    <TransparentCard to={url} linkName={id} external>
      <Separator size="nano" />
      {isSmallScreen ? (
        <Row guttersX="nano">
          <Image src={imageMap[imageString]} width={24} height={24} alt="" />
          <Separator size="sm" />
          <H3 size="H6" supplementary>
            {text}
          </H3>
        </Row>
      ) : (
        <>
          <Image src={imageMap[imageString]} width={48} height={48} alt="" />
          <Separator size="sm" />
          <H3 size="H6" supplementary>
            {text}
          </H3>
        </>
      )}
      <Separator size="xxs" />
      <LinkLookAlike text={linkText} />
      <Separator size="sm" />
    </TransparentCard>
  )
}

export default function Features({ firstSet, secondSet }) {
  const atWidth = usePageWidth()
  return (
    <FlowGrid columnCount={atWidth({ sm: 2, lg: 3, xl: 6 })}>
      {firstSet?.sub?.map((iconLinkdata) => (
        <NavCard key={iconLinkdata.id} {...iconLinkdata} />
      ))}
      {secondSet && MultiLinkSections({ ...secondSet })}
    </FlowGrid>
  )
}
